solution_code:
#include <stdio.h>
#include <stdlib.h>

int *alloc_array(int n) {
    if (n <= 0) return NULL;
    return malloc((size_t)n * sizeof(int));
}

void free_array(int *arr) {
    free(arr);
}

validation.test_code:
int *alloc_array(int n);
void free_array(int *arr);

void test_alloc_returns_non_null(void) {
    int *arr = alloc_array(5);
    TEST_ASSERT_NOT_NULL(arr);
    free_array(arr);
}

void test_alloc_can_store_values(void) {
    int *arr = alloc_array(5);
    TEST_ASSERT_NOT_NULL(arr);
    arr[0] = 1; arr[1] = 2; arr[2] = 3; arr[3] = 4; arr[4] = 5;
    TEST_ASSERT_EQUAL_INT(1, arr[0]);
    TEST_ASSERT_EQUAL_INT(5, arr[4]);
    free_array(arr);
}

void test_alloc_negative_size(void) {
    int *arr = alloc_array(-5);
    TEST_ASSERT_NULL(arr);
}

void test_alloc_zero_size(void) {
    int *arr = alloc_array(0);
    TEST_ASSERT_NULL(arr);
}

void test_alloc_large_array(void) {
    int *arr = alloc_array(100);
    TEST_ASSERT_NOT_NULL(arr);
    arr[0] = 999; arr[99] = 777;
    TEST_ASSERT_EQUAL_INT(999, arr[0]);
    TEST_ASSERT_EQUAL_INT(777, arr[99]);
    free_array(arr);
}

int main(void) {
    RUN_TEST(test_alloc_returns_non_null);
    RUN_TEST(test_alloc_can_store_values);
    RUN_TEST(test_alloc_negative_size);
    RUN_TEST(test_alloc_zero_size);
    RUN_TEST(test_alloc_large_array);
    TEST_SUMMARY();
    return _clings_failures > 0 ? 1 : 0;
}

